@page "/settings"
@rendermode InteractiveServer
@using sv_3b7b9bff3f7e43a8ab9f53562f98a9ce.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <!-- Sidebar Navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                <span class="sidebar-icon">@section.Value.Icon</span>
                <span>@section.Value.Label</span>
            </button>
        }
    </nav>

    <!-- Main Content Area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center p-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="toast-notification @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

<!-- Session Revoke Confirmation Modal -->
@if (_showRevokeDialog)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="() => _showRevokeDialog = false"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
                    <p class="text-muted mb-0">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => _showRevokeDialog = false">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    // ── Section metadata ──
    private record SectionMeta(string Label, string Icon);

    private readonly Dictionary<string, SectionMeta> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨")
    };

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // Toast
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // ── Notifications state ──
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelMuteState> _channels = [];

    private class ChannelMuteState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }

    // ── Security state ──
    private SecuritySettings? _security;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] AvailableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = await profileTask;
        _profile = _savedProfile;
        ResetProfileFields();

        // Notifications
        var notifs = await notifTask;
        _emailNotifications = notifs.EmailNotifications;
        _pushNotifications = notifs.PushNotifications;
        _weeklyDigest = notifs.WeeklyDigest;
        _channels = notifs.MutedChannels
            .Select(c => new ChannelMuteState { Name = c, Muted = true })
            .ToList();

        // Security
        _security = await securityTask;
        _twoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = await appearanceTask;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;
    }

    private void ResetProfileFields()
    {
        _editDisplayName = _savedProfile!.DisplayName;
        _editEmail = _savedProfile.Email;
        _editBio = _savedProfile.Bio;
        _editAvatarUrl = _savedProfile.AvatarUrl;
    }

    // ── Toast helper ──
    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile actions ──
    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _profile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileFields();
    }

    // ── Notification actions ──
    private async Task SaveNotifications()
    {
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // ── Security actions ──
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            await ShowToast("Please fill in all password fields.", true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New passwords do not match.", true);
            return;
        }

        if (_newPassword.Length < 8)
        {
            await ShowToast("Password must be at least 8 characters.", true);
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _showRevokeDialog = false;
        _sessionToRevoke = null;
        _security = await SettingsService.GetSecuritySettingsAsync();
        await ShowToast("Session revoked.");
    }

    // ── Appearance actions ──
    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    // ── Render fragments ──

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h4 class="section-title">Profile</h4>

        <div class="avatar-area mb-4">
            <img src="@_editAvatarUrl" alt="Avatar" class="avatar-preview" />
            <div class="mt-2">
                <label class="form-label text-muted small">Avatar URL</label>
