        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h4 class="section-title">Notifications</h4>

        <div class="settings-card mb-4">
            <h6>General</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="settings-card mb-4">
            <h6>Muted Channels</h6>
            @if (_channels.Count == 0)
            {
                <p class="text-muted">No channels to display.</p>
            }
            else
            {
                @foreach (var channel in _channels)
                {
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                               @bind="channel.Muted" />
                        <label class="form-check-label" for="@($"ch-{channel.Name}")">
                            #@channel.Name
                        </label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h4 class="section-title">Security</h4>

        <!-- Change Password -->
        <div class="settings-card mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h6 class="mb-0">Change Password</h6>
                <button class="btn btn-sm btn-outline-secondary"
                        @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    @(_changePasswordExpanded ? "Collapse" : "Expand")
                </button>
            </div>

            @if (_changePasswordExpanded)
            {
                <div class="mt-3">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                </div>
            }

            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last changed: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="settings-card mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="settings-card">
            <h6>Active Sessions</h6>
            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-sm table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session == _security.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted mb-0">No active sessions.</p>
            }
        </div>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <h4 class="section-title">Appearance</h4>

        <!-- Theme -->
        <div class="settings-card mb-4">
            <h6>Theme</h6>
            <div class="d-flex gap-3">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    var t = theme;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{t}")" value="@t" checked="@(_theme == t)"
                               @onchange="() => _theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>
        </div>

        <!-- Font Size -->
        <div class="settings-card mb-4">
            <h6>Font Size</h6>
            <div class="d-flex gap-3">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    var s = size;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{s}")" value="@s" checked="@(_fontSize == s)"
                               @onchange="() => _fontSize = s" />
                        <label class="form-check-label" for="@($"fs-{s}")">@s</label>
                    </div>
                }
            </div>
        </div>

        <!-- Language -->
        <div class="settings-card mb-4">
            <h6>Language</h6>
            <select class="form-select" style="max-width: 250px;" @bind="_language">
                @foreach (var lang in AvailableLanguages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="settings-card mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="settings-card mb-4">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <h5 style="margin-bottom: 0.5rem;">Dashboard</h5>
                <p style="margin-bottom: 0.5rem;">Welcome back! Here's your overview for today.</p>
                <div class="d-flex gap-2">
                    <button class="btn btn-sm btn-primary">Action</button>
                    <button class="btn btn-sm btn-outline-secondary">Cancel</button>
                </div>
                <p class="mt-2 mb-0 text-muted" style="font-size: 0.8em;">
                    Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </p>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

